import os
import hashlib
import hmac
from datetime import datetime, timedelta
from functools import wraps
from flask import Flask, session, redirect, url_for, request, jsonify

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', 'dev-secret-key-change-in-production')
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(days=7)

users_db = {
    'admin': {
        'password': hashlib.sha256(b'admin123').hexdigest(),
        'email': 'admin@example.com'
    },
    'user': {
        'password': hashlib.sha256(b'user123').hexdigest(),
        'email': 'user@example.com'
    }
}

sessions_db = {}


def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()


def verify_password(stored_password, provided_password):
    return stored_password == hash_password(provided_password)


def create_session(username):
    session.permanent = True
    session['username'] = username
    session['login_time'] = datetime.now().isoformat()
    session['authenticated'] = True
    
    session_id = generate_session_id(username)
    sessions_db[session_id] = {
        'username': username,
        'created_at': datetime.now(),
        'last_activity': datetime.now()
    }
    session['session_id'] = session_id
    
    return session_id


def generate_session_id(username):
    random_bytes = os.urandom(32)
    message = f"{username}{datetime.now().isoformat()}".encode()
    return hmac.new(random_bytes, message, hashlib.sha256).hexdigest()


def destroy_session():
    session_id = session.get('session_id')
    if session_id and session_id in sessions_db:
        del sessions_db[session_id]
    session.clear()


def is_session_valid():
    if not session.get('authenticated'):
        return False
    
    session_id = session.get('session_id')
    if not session_id or session_id not in sessions_db:
        return False
    
    session_data = sessions_db[session_id]
    last_activity = session_data['last_activity']
    
    timeout = timedelta(hours=24)
    if datetime.now() - last_activity > timeout:
        destroy_session()
        return False
    
    sessions_db[session_id]['last_activity'] = datetime.now()
    return True


def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not is_session_valid():
            return redirect(url_for('login', next=request.url))
        return f(*args, **kwargs)
    return decorated_function


@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        remember = request.form.get('remember', False)
        
        if username in users_db:
            if verify_password(users_db[username]['password'], password):
                create_session(username)
                
                if remember:
                    session.permanent = True
                else:
                    session.permanent = False
                    app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(hours=2)
                
                next_page = request.args.get('next')
                if next_page:
                    return redirect(next_page)
                return redirect(url_for('dashboard'))
            else:
                return jsonify({'error': 'Invalid credentials'}), 401
        else:
            return jsonify({'error': 'User not found'}), 404
    
    return '''
        <form method="post">
            <input type="text" name="username" placeholder="Username" required>
            <input type="password" name="password" placeholder="Password" required>
            <label><input type="checkbox" name="remember" value="1"> Remember me</label>
            <button type="submit">Login</button>
        </form>
    '''


@app.route('/logout')
def logout():
    destroy_session()
    return redirect(url_for('login'))


@app.route('/dashboard')
@login_required
def dashboard():
    username = session.get('username')
    login_time = session.get('login_time')
    return f'''
        <h1>Welcome, {username}!</h1>
        <p>Logged in at: {login_time}</p>
        <a href="{url_for('profile')}">Profile</a> | 
        <a href="{url_for('logout')}">Logout</a>
    '''


@app.route('/profile')
@login_required
def profile():
    username = session.get('username')
    user_data = users_db.get(username, {})
    return jsonify({
        'username': username,
        'email': user_data.get('email'),
        'login_time': session.get('login_time')
    })


@app.route('/session/info')
@login_required
def session_info():
    session_id = session.get('session_id')
    session_data = sessions_db.get(session_id, {})
    
    return jsonify({
        'username': session.get('username'),
        'session_id': session_id,
        'authenticated': session.get('authenticated'),
        'permanent': session.permanent,
        'created_at': session_data.get('created_at').isoformat() if session_data.get('created_at') else None,
        'last_activity': session_data.get('last_activity').isoformat() if session_data.get('last_activity') else None
    })


@app.route('/')
def index():
    if is_session_valid():
        return redirect(url_for('dashboard'))
    return redirect(url_for('login'))


if __name__ == '__main__':
    app.run(debug=True)